// This file is generated by AI.

use path_tree::{Folder, Node};

#[test]
fn sorting_order_preserved() {
    let data = vec![("d/c", 1), ("a/z", 2), ("b/x", 3), ("a/a", 4)];
    let folder = Folder::from_vec(data);
    // each top-level folder should be in sorted order
    let top: Vec<&str> = folder.iter().map(|(n, _)| n).collect();
    assert_eq!(top, vec!["a", "b", "d"]);
}

#[test]
fn case_sensitivity() {
    let folder = Folder::from_vec(vec![("File", 1), ("file", 2)]);
    assert_eq!(folder.get("File").and_then(|n| n.as_item()), Some(&1));
    assert_eq!(folder.get("file").and_then(|n| n.as_item()), Some(&2));
}

#[test]
fn very_long_path_no_panic() {
    let long_segment = "a".repeat(1200);
    let path = format!("{}/b", long_segment);
    let folder = Folder::from_vec(vec![(path.clone(), 1)]);
    assert_eq!(folder.get(&path).and_then(|n| n.as_item()), Some(&1));
}

#[test]
fn large_number_of_siblings() {
    let mut data = Vec::new();
    for i in 0..600 {
        data.push((format!("leaf{}", i), i));
    }
    let folder = Folder::from_vec(data.clone());
    assert_eq!(folder.iter().count(), 600);
    // spot-check a few values
    for i in [0usize, 10, 199, 599].iter() {
        let key = format!("leaf{}", i);
        assert_eq!(folder.get(&key).and_then(|n| n.as_item()), Some(i));
    }
}

#[test]
fn deep_structure_no_stack_overflow() {
    let depth = 1000usize;
    let path = make_deep_path(depth);
    let folder = Folder::from_vec(vec![(path.clone(), 1)]);
    assert_eq!(folder.get(&path).and_then(|n| n.as_item()), Some(&1));
    // iter_recursively should visit each level
    assert_eq!(folder.iter_recursively().count(), depth);
}

#[test]
fn remove_folder_entire_subtree() {
    let mut folder: Folder<i32> = Folder::new();
    folder.insert("a/b/c", Node::Item(1));
    let removed = folder.remove("a/b");
    assert!(removed.is_some());
    assert!(folder.get("a/b/c").is_none());
}

#[test]
fn remove_intermediate_cascades_upwards() {
    let mut root: Folder<i32> = Folder::new();
    root.insert("a/b/c", Node::Item(1));
    let removed = root.remove("a/b").expect("should remove folder");
    assert!(removed.into_folder().is_some());
    // child removed
    assert!(root.get("a/b/c").is_none());
    // parent 'a' should be cleaned up if empty
    assert!(root.get("a").is_none());
}

#[test]
fn insert_into_existing_folder_merges() {
    let mut folder: Folder<i32> = Folder::new();
    folder.insert("a/b", Node::Item(1));
    folder.insert("a/c", Node::Item(2));
    let a = folder
        .get("a")
        .and_then(|n| n.as_folder())
        .expect("a should be folder");
    let names: Vec<&str> = a.iter().map(|(n, _)| n).collect();
    assert_eq!(names, vec!["b", "c"]);
}

#[test]
fn recursive_iter_path_no_trailing_slash() {
    let folder = Folder::from_vec(vec![("a/b", 1), ("a/c/d", 2)]);
    for (p, _) in folder.iter_recursively() {
        assert!(!p.ends_with('/'));
        let normalized = p.trim_start_matches('/');
        assert!(!normalized.is_empty());
    }
}

pub fn make_deep_path(depth: usize) -> String {
    (0..depth)
        .map(|i| format!("p{}", i))
        .collect::<Vec<_>>()
        .join("/")
}
